const items = $input.first().json.items || [];
const rows = items.map(v => ({ title: v.snippet.title, views: parseInt((v.statistics && v.statistics.viewCount) || '0', 10) })).sort((a, b) => b.views - a.views);
const text = rows.slice(0, 10).map((r, i) => `${i + 1}. ${r.title} — ${r.views.toLocaleString('ru-RU')} просмотров`).join('\n');
return [{ json: { yt_text: text, yt_list: rows } }];

const raw = $input.first().json.candidates[0].content.parts[0].text;
const clean = raw.trim().replace(/^```json/i, '').replace(/^```/, '').replace(/```$/, '').trim();
const script = JSON.parse(clean);
let sources = [];
try {
  const gm = $('Research').first().json.candidates[0].groundingMetadata;
  const chunks = (gm && gm.groundingChunks) || [];
  sources = chunks.map(c => c.web && c.web.uri).filter(Boolean);
} catch (e) {}
script.sources = sources;
script.youtube_refs = $('YT top').first().json.yt_list.slice(0, 5);
return [{ json: script }];
